    "call_to_action": {
      "banner_text": "Limited to first-time buyers",
      "buttons": {
        "count": 2,
        "labels": [
          "Try it at a discount",
          "See details"
        ]
      }
    },
    "statistics_cards": {
      "count": 4,
      "style": "white rectangular cards with large teal numbers",
      "labels": [
        "Satisfaction 92%",
        "Pore visibility -23%",
        "Acne prevention 87%",
        "Want to repeat 97%"
      ]
    }
  }
}

{
  "type": "学术试卷",
  "header": {
    "student_info": [
      "姓名：",
